/**
 * The Meaning of Life — Untangling (Pass 60.6)
 *
 * Implements the sustained application of Reidemeister simplification rules
 * upon unresolvable Humor "Hope Gaps" or traumatic psychological knots.
 * Maps meaning not as an absolute destination, but as the procedural
 * act of Untangling (lowering crossing complexity via continuous Fold/Vent logic).
 */

export interface PsychologicalKnot {
  /** Total crossings (ambiguity intersections) currently held in memory */
  crossings: number;
  /** True if the knot is in a deadlock state (Hope Gap failure) */
  isHopeGap: boolean;
}

export type UntangleOperation = 'R1_untwist' | 'R2_poke' | 'R3_slide' | 'vent_bleed';

/**
 * Procedural Untangling
 *
 * Rather than collapsing the logic instantly (Punchline), this method applies 
 * systemic Reidemeister Operations to slowly pull a Hope Gap apart until it
 * degrades into an unknot.
 */
export function executeUntangling(knot: PsychologicalKnot, operation: UntangleOperation): PsychologicalKnot {
  if (knot.crossings === 0) {
    return { ...knot, crossings: 0, isHopeGap: false };
  }

  let crossingReduction = 0;
  
  switch (operation) {
    case 'R1_untwist':
      crossingReduction = 1;
      break;
    case 'R2_poke':
      crossingReduction = 2; // Pulls two adjacent overlapping lines apart
      break;
    case 'R3_slide':
      crossingReduction = 0; // Does not reduce crossings, merely shifts topology for next move
      break;
    case 'vent_bleed':
      crossingReduction = 1; // Bleeding off the deadlock heat
      break;
  }

  const newCrossings = Math.max(0, knot.crossings - crossingReduction);
  
  return {
    crossings: newCrossings,
    // If the crossings are dropping, the Hope Gap deadlock has been broken
    isHopeGap: newCrossings > 0 && knot.isHopeGap && operation === 'R3_slide'
  };
}
